import React, { useEffect, useMemo, useState } from 'react';
import {
    createCustomer,
    CreateCustomerInput,
    Customer,
    fetchCustomerById,
    fetchCustomers,
    updateCustomer,
    UpdateCustomerInput,
} from '../api/customers';

type FormMode = 'create' | 'edit';

interface CustomerFormState {
    name: string;
    email: string;
    plan: string;
    status: 'Ativo' | 'Suspenso';
}

const emptyForm: CustomerFormState = {
    name: '',
    email: '',
    plan: '',
    status: 'Ativo',
};

const Customers: React.FC = () => {
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [loading, setLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);
    const [successMessage, setSuccessMessage] = useState<string | null>(null);

    const [search, setSearch] = useState<string>('');
    const [currentPage, setCurrentPage] = useState<number>(1);

    const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
    const [detailsLoading, setDetailsLoading] = useState<boolean>(false);
    const [formMode, setFormMode] = useState<FormMode>('create');
    const [formData, setFormData] = useState<CustomerFormState>(emptyForm);
    const [saving, setSaving] = useState<boolean>(false);

    const pageSize = 4;

    useEffect(() => {
        const load = async () => {
            try {
                const list = await fetchCustomers();
                setCustomers(list);
            } catch (err) {
                setError('Falha ao carregar clientes.');
            } finally {
                setLoading(false);
            }
        };

        load();
    }, []);

    useEffect(() => {
        if (!successMessage) return;

        const timer = window.setTimeout(() => {
            setSuccessMessage(null);
        }, 2500);

        return () => window.clearTimeout(timer);
    }, [successMessage]);

    const filteredCustomers = useMemo(() => {
        const term = search.trim().toLowerCase();
        if (!term) return customers;

        return customers.filter(
            (customer) =>
                customer.name.toLowerCase().includes(term)
                || customer.email.toLowerCase().includes(term)
                || customer.plan.toLowerCase().includes(term),
        );
    }, [customers, search]);

    const totalPages = Math.max(1, Math.ceil(filteredCustomers.length / pageSize));
    const safePage = Math.min(currentPage, totalPages);
    const start = (safePage - 1) * pageSize;
    const paginatedCustomers = filteredCustomers.slice(start, start + pageSize);

    const handlePrev = () => setCurrentPage((prev) => Math.max(1, prev - 1));
    const handleNext = () => setCurrentPage((prev) => Math.min(totalPages, prev + 1));

    const openCreateForm = () => {
        setError(null);
        setFormMode('create');
        setSelectedCustomer(null);
        setFormData(emptyForm);
    };

    const openEditForm = async (id: string) => {
        setError(null);
        setDetailsLoading(true);
        try {
            const customer = await fetchCustomerById(id);
            if (!customer) {
                setError('Cliente não encontrado para edição.');
                return;
            }

            setFormMode('edit');
            setSelectedCustomer(customer);
            setFormData({
                name: customer.name,
                email: customer.email,
                plan: customer.plan,
                status: customer.status,
            });
        } catch (err) {
            setError('Falha ao carregar cliente para edição.');
        } finally {
            setDetailsLoading(false);
        }
    };

    const openViewDetails = async (id: string) => {
        setError(null);
        setDetailsLoading(true);
        try {
            const customer = await fetchCustomerById(id);
            if (!customer) {
                setError('Cliente não encontrado para visualização.');
                return;
            }

            setSelectedCustomer(customer);
            setFormMode('create');
        } catch (err) {
            setError('Falha ao carregar detalhes do cliente.');
        } finally {
            setDetailsLoading(false);
        }
    };

    const handleFormChange = (field: keyof CustomerFormState, value: string) => {
        setFormData((prev) => ({ ...prev, [field]: value }));
    };

    const reloadCustomers = async () => {
        const list = await fetchCustomers();
        setCustomers(list);
    };

    const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
        event.preventDefault();
        setError(null);

        if (!formData.name.trim() || !formData.email.trim() || !formData.plan.trim()) {
            setError('Preencha nome, email e plano para salvar o cliente.');
            return;
        }

        setSaving(true);
        try {
            if (formMode === 'create') {
                const payload: CreateCustomerInput = {
                    name: formData.name,
                    email: formData.email,
                    plan: formData.plan,
                    status: formData.status,
                };

                const created = await createCustomer(payload);
                setSelectedCustomer(created);
                setSuccessMessage('Cliente adicionado com sucesso.');
            } else if (selectedCustomer) {
                const payload: UpdateCustomerInput = {
                    name: formData.name,
                    email: formData.email,
                    plan: formData.plan,
                    status: formData.status,
                };

                const updated = await updateCustomer(selectedCustomer.id, payload);
                if (!updated) {
                    setError('Não foi possível atualizar este cliente.');
                    return;
                }

                setSelectedCustomer(updated);
                setSuccessMessage('Cliente atualizado com sucesso.');
            }

            await reloadCustomers();
        } catch (err) {
            setError('Falha ao salvar cliente.');
        } finally {
            setSaving(false);
        }
    };

    return (
        <div style={{ padding: '1rem 1.25rem' }}>
            <h1>Clientes</h1>
            <p style={{ color: '#475569' }}>Gestão visual de clientes com inclusão, edição e visualização de dados.</p>
            {loading && <p>Carregando clientes...</p>}
            {error && <p style={{ color: '#b91c1c' }}>{error}</p>}
            {successMessage && <p style={{ color: '#0f766e' }}>{successMessage}</p>}

            <div style={{ marginBottom: '0.8rem', display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                <button onClick={openCreateForm}>+ Novo cliente</button>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1rem', alignItems: 'start' }}>
                <section>
                    <div style={{ marginBottom: '0.8rem' }}>
                        <input
                            type="text"
                            placeholder="Buscar por nome, email ou plano..."
                            value={search}
                            onChange={(e) => {
                                setSearch(e.target.value);
                                setCurrentPage(1);
                            }}
                            style={{ width: '100%', maxWidth: 420, padding: '0.5rem 0.65rem', border: '1px solid #cbd5e1', borderRadius: 8 }}
                        />
                    </div>

                    <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff', border: '1px solid #e2e8f0' }}>
                        <thead>
                            <tr style={{ background: '#f1f5f9' }}>
                                <th>ID</th>
                                <th>Nome</th>
                                <th>Email</th>
                                <th>Plano</th>
                                <th>Status</th>
                                <th>Ações</th>
                            </tr>
                        </thead>
                        <tbody>
                            {!loading && paginatedCustomers.map((customer) => (
                                <tr key={customer.id}>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>{customer.id}</td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>{customer.name}</td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>{customer.email}</td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>{customer.plan}</td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>{customer.status}</td>
                                    <td style={{ padding: '0.5rem', borderTop: '1px solid #e2e8f0' }}>
                                        <div style={{ display: 'flex', gap: '0.4rem', flexWrap: 'wrap' }}>
                                            <button onClick={() => openViewDetails(customer.id)}>Ver</button>
                                            <button onClick={() => openEditForm(customer.id)}>Editar</button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                            {paginatedCustomers.length === 0 && (
                                <tr>
                                    <td style={{ padding: '0.75rem', textAlign: 'center', borderTop: '1px solid #e2e8f0' }} colSpan={6}>
                                        Nenhum cliente encontrado.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>

                    <div style={{ marginTop: '0.8rem', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <button onClick={handlePrev} disabled={safePage === 1}>Anterior</button>
                        <span>Página {safePage} de {totalPages}</span>
                        <button onClick={handleNext} disabled={safePage === totalPages}>Próxima</button>
                        <small style={{ color: '#64748b' }}>
                            {filteredCustomers.length} cliente(s) filtrado(s)
                        </small>
                    </div>
                </section>

                <aside style={{ background: '#fff', border: '1px solid #e2e8f0', borderRadius: 10, padding: '0.9rem' }}>
                    <h3 style={{ marginTop: 0 }}>
                        {formMode === 'create' ? 'Adicionar cliente' : 'Editar cliente'}
                    </h3>

                    <form onSubmit={handleSubmit} style={{ display: 'grid', gap: '0.6rem' }}>
                        <label>
                            <div>Nome</div>
                            <input value={formData.name} onChange={(e) => handleFormChange('name', e.target.value)} />
                        </label>

                        <label>
                            <div>Email</div>
                            <input type="email" value={formData.email} onChange={(e) => handleFormChange('email', e.target.value)} />
                        </label>

                        <label>
                            <div>Plano</div>
                            <input value={formData.plan} onChange={(e) => handleFormChange('plan', e.target.value)} />
                        </label>

                        <label>
                            <div>Status</div>
                            <select value={formData.status} onChange={(e) => handleFormChange('status', e.target.value)}>
                                <option value="Ativo">Ativo</option>
                                <option value="Suspenso">Suspenso</option>
                            </select>
                        </label>

                        <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                            <button type="submit" disabled={saving}>
                                {saving ? 'Salvando...' : formMode === 'create' ? 'Adicionar' : 'Salvar edição'}
                            </button>
                            <button type="button" onClick={openCreateForm}>Limpar</button>
                        </div>
                    </form>

                    <hr style={{ margin: '0.9rem 0' }} />

                    <h4 style={{ marginTop: 0 }}>Visualização</h4>
                    {detailsLoading && <p>Carregando detalhes...</p>}
                    {!detailsLoading && !selectedCustomer && (
                        <p style={{ color: '#64748b' }}>Selecione um cliente em “Ver” ou “Editar”.</p>
                    )}
                    {!detailsLoading && selectedCustomer && (
                        <div style={{ display: 'grid', gap: '0.35rem' }}>
                            <div><strong>ID:</strong> {selectedCustomer.id}</div>
                            <div><strong>Nome:</strong> {selectedCustomer.name}</div>
                            <div><strong>Email:</strong> {selectedCustomer.email}</div>
                            <div><strong>Plano:</strong> {selectedCustomer.plan}</div>
                            <div><strong>Status:</strong> {selectedCustomer.status}</div>
                        </div>
                    )}
                </aside>
            </div>
        </div>
    );
};

export default Customers;
